#include <vector>
#include <queue>
#include <climits>

using namespace std;

long long solve(vector<vector<long long>> grid, long long k) {
    int m = grid.size();
    int n = grid[0].size();
    vector<vector<vector<int>>> visited(m, vector<vector<int>>(n, vector<int>(k + 1, -1)));
    queue<vector<int>> queue;
    queue.push({0, 0, 0, 0}); // [row, col, cost, used_transports]
    vector<pair<int, int>> directions = {{0, 1}, {1, 0}};

    while (!queue.empty()) {
        vector<int> current = queue.front();
        queue.pop();
        int row = current[0], col = current[1], cost = current[2], used = current[3];

        if (row == m - 1 && col == n - 1) {
            return cost;
        }

        if (visited[row][col][used] != -1) {
            continue;
        }
        visited[row][col][used] = cost;

        // Regular moves (right and down)
        for (auto [dr, dc] : directions) {
            int new_row = row + dr, new_col = col + dc;
            if (new_row < m && new_col < n) {
                long long new_cost = cost + grid[new_row][new_col];
                queue.push({new_row, new_col, new_cost, used});
            }
        }

        // Teleportation
        if (used < k) {
            for (int x = 0; x < m; ++x) {
                for (int y = 0; y < n; ++y) {
                    if (grid[x][y] <= grid[row][col]) {
                        queue.push({x, y, cost, used + 1});
                    }
                }
            }
        }
    }

    return -1;
}
